# PowerShell: register a provider
Register-AzResourceProvider -ProviderNamespace Microsoft.ContainerService

# Wait for registration to complete
do {
  $state = (Get-AzResourceProvider -ProviderNamespace Microsoft.ContainerService).RegistrationState
  Write-Host "State: $state"
  if ($state -ne 'Registered') { Start-Sleep -Seconds 10 }
} while ($state -ne 'Registered')
Write-Host 'Registered'

// Bicep: deploying any resource automatically registers its provider
// This requires the deploying principal to have Contributor on the subscription

// When you deploy this, ARM registers Microsoft.ContainerService if not already registered:
resource aks 'Microsoft.ContainerService/managedClusters@2023-08-01' = {
  name: 'aks-myapp-prod-eus2'
  location: resourceGroup().location
  identity: { type: 'SystemAssigned' }
  properties: {
    dnsPrefix: 'myapp-prod'
    agentPoolProfiles: [
      {
        name: 'system'
        count: 2
        vmSize: 'Standard_D2s_v5'
        mode: 'System'
      }
    ]
  }
}

// Explicit registration step (useful in service principal contexts
// where auto-register may fail due to missing subscription-level permissions)
// Run before the deployment:
// az provider register --namespace Microsoft.ContainerService

# Azure Policy: audit providers that are NOT registered
# Use this to detect subscriptions missing required providers

# Built-in policy: 'Allowed resource types'
# (prevents deploying resources from non-whitelisted providers)
az policy definition show \
  --name 'a08ec900-254a-4555-9bf5-e42af04b5c5c' \
  --query displayName -o tsv
# Allowed resource types

# Custom audit policy: flag subscriptions where Microsoft.Security is not registered
POLICY='{
  "if": {
    "allOf": [
      {"field": "type", "equals": "Microsoft.Resources/subscriptions"},
      {"not": {"anyOf": [
        {"field": "Microsoft.Resources/subscriptions/providers/registrationState",
         "equals": "Registered"}
      ]}}
    ]
  },
  "then": {"effect": "audit"}
}'

